sql:
SELECT users.user_name, users.role, access_logs.access_duration
FROM users
JOIN access_logs ON users.user_id = access_logs.user_id;

SELECT airline_name, fleet_size
FROM airlines
WHERE fleet_size = (SELECT MAX(fleet_size) FROM airlines);

external_knowledge:
- "flight havens" refers to airports;
- "more runways than a typical four-lane highway" metaphorically means having more than three runways;
- "from the last star in the night sky to the first" metaphorically refers to ordering the results in descending order by the airport name.

sql:
SELECT *
FROM delays
WHERE delay_type = 'carrier' AND flight_id = 1;

external_knowledge:
'Last month' refers to the time between May 1, 2023, and May 31, 2023;
'Active managers' are users with the role 'operations manager' and an active status;
'Have a contact email' means that the contact email for the airline is not null.

sql:
SELECT maintenance_status, last_maintenance_date
FROM flight_aircraft
WHERE flight_id > 1;
